# Resolve directory of the script
script_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# Move three levels up
target_dir="$(cd "$script_dir/../../.." && pwd)"

# Ensure directory exists
mkdir -p "$target_dir/_testing/sm_worker"

# Create or update debug file
touch "$target_dir/_testing/sm_worker/bash_param.debug"

# Set permissions recursively
chmod -R 0777 "$target_dir/_testing/"

# Save the first argument to debug file
echo "$2" > "$target_dir/_testing/sm_worker/bash_param.debug"
